FILES: dict[str, str] = {'README_APPLY_4B436629D.txt': '4B.4.3.6.6.29D Replay / Backtest / Walk-forward Gate\n\nApply:\n  cd C:\\Users\\muhas\\OneDrive\\Masaüstü\\trade_botV2\n  Expand-Archive -Path "$env:USERPROFILE\\Downloads\\trade_botV2_4B436629D_replay_backtest_walkforward_gate_deterministic_replay_model_hash_lkg_oos_gate_patch.zip" -DestinationPath . -Force\n  python tools/apply_4B436629D_replay_backtest_walkforward_gate.py\n\nVerify:\n  $env:PYTHONPATH="src"\n  python tools/check_4B436629D_replay_backtest_walkforward_gate.py --once-json\n  $env:PYTEST_DISABLE_PLUGIN_AUTOLOAD="1"\n  $env:PYTHONPATH="src"\n  python -m pytest -q tests/test_replay_backtest_walkforward_gate_4B436629D.py\n  python -m compileall -q -x \'(_patch_backup|_patch_payload|legacy_patches)\' src tools tests\n\nReport:\n  $env:PYTHONPATH="src"\n  python tools/run_4B436629D_replay_backtest_walkforward_gate.py --reports-dir .\\reports\\production_hardening\n\nExpected decision:\n  REPLAY_BACKTEST_WALKFORWARD_GATE_READY_LIVE_REAL_STILL_BLOCKED\n', 'tests/test_replay_backtest_walkforward_gate_4B436629D.py': 'from __future__ import annotations\n\nfrom pathlib import Path\n\nfrom tradebot.replay_gate import build_walk_forward_windows, deterministic_decision_replay_digest, evaluate_oos_report_gate, hash_model_artifact, load_last_known_good_registry, register_last_known_good_model, verify_replay_digest\n\n\ndef test_deterministic_replay_digest_is_stable() -> None:\n    rows_a = [{"ts": 1, "signal": "HOLD", "score": 0.12}, {"signal": "SELL", "ts": 2, "score": 0.81}]\n    rows_b = [{"score": 0.12, "signal": "HOLD", "ts": 1}, {"score": 0.81, "ts": 2, "signal": "SELL"}]\n    digest_a = deterministic_decision_replay_digest(rows_a)\n    digest_b = deterministic_decision_replay_digest(rows_b)\n    assert digest_a.digest == digest_b.digest\n    assert verify_replay_digest(rows_b, digest_a.digest).ok is True\n\n\ndef test_model_artifact_hash_and_lkg_registry(tmp_path: Path) -> None:\n    model = tmp_path / "model.ubj"\n    model.write_bytes(b"stable-model-bytes")\n    manifest = hash_model_artifact(model, metadata={"symbol": "BNBUSDT"})\n    registry_path = tmp_path / "last_known_good_model_registry.json"\n    registry = register_last_known_good_model(registry_path, manifest, reason="OOS_GATE_ACCEPTED_FOR_REVIEW_ONLY", gate_snapshot={"approved_for_live_real": False})\n    loaded = load_last_known_good_registry(registry_path)\n    assert registry["latest"]["manifest"]["sha256"] == manifest.sha256\n    assert loaded["latest"]["manifest"]["metadata"]["symbol"] == "BNBUSDT"\n\n\ndef test_oos_gate_blocks_runtime_even_when_review_candidate() -> None:\n    decision = evaluate_oos_report_gate({"matured_count": 31, "win_rate_pct": 65.0, "profit_factor": 1.8, "mean_return_bps": 12.5, "worst_return_bps": -220.0, "worst_mae_bps": -300.0, "unique_oos_days": 3, "regime_count": 2, "measurement_guard_pass": True})\n    assert decision.approved_for_promotion_review_candidate is True\n    assert decision.approved_for_runtime_overlay_activation_candidate is False\n    assert decision.approved_for_paper_candidate is False\n    assert decision.approved_for_live_real is False\n\n\ndef test_oos_gate_rejects_small_sample_and_tail_risk() -> None:\n    decision = evaluate_oos_report_gate({"matured_count": 13, "win_rate_pct": 76.9, "profit_factor": 5.4, "mean_return_bps": 126.6, "worst_return_bps": -312.0, "worst_mae_bps": -426.0, "unique_oos_days": 1, "regime_count": 1, "tail_risk_worsened": True})\n    assert decision.approved_for_promotion_review_candidate is False\n    assert "OOS_MATURED_COUNT_BELOW_MIN" in decision.reason_codes\n    assert "OOS_TAIL_RISK_WORSENED" in decision.reason_codes\n\n\ndef test_walk_forward_windows_are_deterministic() -> None:\n    windows = build_walk_forward_windows(total_samples=100, train_size=40, test_size=10, step_size=10)\n    assert [w.to_dict() for w in windows[:2]] == [\n        {"window_id": 1, "train_start": 0, "train_end": 40, "test_start": 40, "test_end": 50},\n        {"window_id": 2, "train_start": 10, "train_end": 50, "test_start": 50, "test_end": 60},\n    ]\n', 'tools/check_4B436629D_replay_backtest_walkforward_gate.py': 'from __future__ import annotations\n\nimport argparse\nimport importlib.util\nimport json\nimport py_compile\nimport sys\nimport tempfile\nfrom pathlib import Path\nfrom typing import Any\n\nCONTRACT_VERSION = "4B.4.3.6.6.29D"\nEXPECTED_FILES = [\n    "src/tradebot/replay_gate.py",\n    "tests/test_replay_backtest_walkforward_gate_4B436629D.py",\n    "tools/apply_4B436629D_replay_backtest_walkforward_gate.py",\n    "tools/check_4B436629D_replay_backtest_walkforward_gate.py",\n    "tools/run_4B436629D_replay_backtest_walkforward_gate.py",\n    "tools/rollback_4B436629D_replay_backtest_walkforward_gate.py",\n    "docs/REPLAY_BACKTEST_WALKFORWARD_GATE_4B436629D.md",\n]\n\n\ndef _read(path: Path) -> str:\n    return path.read_text(encoding="utf-8") if path.exists() else ""\n\n\ndef _compile(path: Path) -> bool:\n    try:\n        py_compile.compile(str(path), doraise=True)\n        return True\n    except Exception:\n        return False\n\n\ndef _load(root: Path):\n    spec = importlib.util.spec_from_file_location("tradebot.replay_gate", root / "src/tradebot/replay_gate.py")\n    if spec is None or spec.loader is None:\n        raise RuntimeError("Could not load replay_gate")\n    module = importlib.util.module_from_spec(spec)\n    sys.modules[spec.name] = module\n    spec.loader.exec_module(module)\n    return module\n\n\ndef _probe(root: Path) -> dict[str, Any]:\n    module = _load(root)\n    rows = [{"ts": 1, "signal": "HOLD"}, {"ts": 2, "signal": "SELL"}]\n    digest = module.deterministic_decision_replay_digest(rows)\n    verify = module.verify_replay_digest(rows, digest.digest)\n    decision = module.evaluate_oos_report_gate({\n        "matured_count": 31,\n        "win_rate_pct": 65.0,\n        "profit_factor": 1.9,\n        "mean_return_bps": 11.0,\n        "worst_return_bps": -200.0,\n        "worst_mae_bps": -250.0,\n        "unique_oos_days": 3,\n        "regime_count": 2,\n        "measurement_guard_pass": True,\n    })\n    blocked = module.evaluate_oos_report_gate({"matured_count": 13, "tail_risk_worsened": True})\n    windows = module.build_walk_forward_windows(total_samples=80, train_size=40, test_size=10, step_size=10)\n    with tempfile.TemporaryDirectory() as tmp:\n        model = Path(tmp) / "model.ubj"\n        model.write_bytes(b"probe-model")\n        manifest = module.hash_model_artifact(model)\n        registry = module.register_last_known_good_model(Path(tmp) / "lkg.json", manifest, reason="PROBE")\n    return {\n        "ok": bool(verify.ok and decision.approved_for_promotion_review_candidate and not decision.approved_for_live_real and not blocked.approved_for_promotion_review_candidate and windows and registry.get("latest")),\n        "digest_ok": bool(verify.ok),\n        "review_candidate_only": bool(decision.approved_for_promotion_review_candidate and not decision.approved_for_live_real),\n        "small_sample_blocked": "OOS_MATURED_COUNT_BELOW_MIN" in blocked.reason_codes,\n        "tail_risk_blocked": "OOS_TAIL_RISK_WORSENED" in blocked.reason_codes,\n        "walk_forward_window_count": len(windows),\n        "model_hash_len": len(manifest.sha256),\n        "registry_latest_present": bool(registry.get("latest")),\n    }\n\n\ndef build_report(root: Path) -> dict[str, Any]:\n    expected = {path: (root / path).exists() for path in EXPECTED_FILES}\n    compiled = {path: _compile(root / path) for path in EXPECTED_FILES if path.endswith(".py") and (root / path).exists()}\n    config_text = _read(root / "src/tradebot/config.py")\n    module_text = _read(root / "src/tradebot/replay_gate.py")\n    try:\n        probe = _probe(root)\n    except Exception as exc:\n        probe = {"ok": False, "error": f"{type(exc).__name__}: {exc}"}\n    checks = {\n        "all_expected_files_present": all(expected.values()),\n        "all_py_compile_ok": all(compiled.values()) if compiled else False,\n        "contract_version_ok": f\'REPLAY_GATE_CONTRACT_VERSION = "{CONTRACT_VERSION}"\' in module_text,\n        "deterministic_replay_digest_present": "deterministic_decision_replay_digest" in module_text,\n        "model_artifact_hash_present": "hash_model_artifact" in module_text and "sha256" in module_text,\n        "last_known_good_registry_present": "register_last_known_good_model" in module_text,\n        "walk_forward_gate_present": "build_walk_forward_windows" in module_text,\n        "oos_report_gate_present": "evaluate_oos_report_gate" in module_text,\n        "promotion_review_only_guard_present": "approved_for_promotion_review_candidate" in module_text and "approved_for_live_real=False" in module_text,\n        "config_replay_gate_fields_present": "replay_gate_enabled" in config_text and "last_known_good_model_registry_path" in config_text,\n        "module_probe_ok": bool(probe.get("ok")),\n        "runtime_activation_blocked": "approved_for_runtime_overlay_activation_candidate=False" in module_text,\n        "paper_live_order_blocked": "approved_for_paper_candidate=False" in module_text and "approved_for_live_real=False" in module_text,\n        "training_reload_blocked": "training_reload_blocked=True" in module_text,\n    }\n    return {\n        "ok": all(checks.values()),\n        "contract_version": CONTRACT_VERSION,\n        "read_only": True,\n        "replay_backtest_walkforward_gate": True,\n        "expected_files": expected,\n        "compiled": compiled,\n        "checks": checks,\n        "module_probe": probe,\n        "hyp006_strategy_threshold_mutation_performed": False,\n        "scheduler_mutation_performed": False,\n        "strategy_parameter_mutation_performed": False,\n        "runtime_overlay_activation_performed": False,\n        "training_performed": False,\n        "reload_performed": False,\n        "trading_action_performed": False,\n        "paper_live_order_enablement_present": False,\n    }\n\n\ndef main() -> int:\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--once-json", action="store_true")\n    parser.parse_args()\n    report = build_report(Path.cwd())\n    print(json.dumps(report, ensure_ascii=False, indent=2, sort_keys=True))\n    return 0 if report["ok"] else 2\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'tools/run_4B436629D_replay_backtest_walkforward_gate.py': 'from __future__ import annotations\n\nimport argparse\nimport json\nfrom datetime import datetime, timezone\nfrom pathlib import Path\n\nfrom check_4B436629D_replay_backtest_walkforward_gate import CONTRACT_VERSION, build_report\n\n\ndef main() -> int:\n    parser = argparse.ArgumentParser(description="Generate 4B.4.3.6.6.29D replay/backtest/walk-forward gate report")\n    parser.add_argument("--reports-dir", default="reports/production_hardening")\n    args = parser.parse_args()\n    report = build_report(Path.cwd())\n    now = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")\n    payload = {\n        "ok": bool(report.get("ok")),\n        "contract_version": CONTRACT_VERSION,\n        "decision": "REPLAY_BACKTEST_WALKFORWARD_GATE_READY_LIVE_REAL_STILL_BLOCKED" if report.get("ok") else "REPLAY_BACKTEST_WALKFORWARD_GATE_NOT_READY",\n        "generated_at_utc": datetime.now(timezone.utc).isoformat(),\n        "read_only": True,\n        "approved_for_deterministic_replay_baseline": bool(report["checks"].get("deterministic_replay_digest_present")),\n        "approved_for_model_artifact_hash_baseline": bool(report["checks"].get("model_artifact_hash_present")),\n        "approved_for_last_known_good_registry_baseline": bool(report["checks"].get("last_known_good_registry_present")),\n        "approved_for_walk_forward_gate_baseline": bool(report["checks"].get("walk_forward_gate_present")),\n        "approved_for_oos_report_gate_baseline": bool(report["checks"].get("oos_report_gate_present")),\n        "approved_for_promotion_review_candidate_only": bool(report["checks"].get("promotion_review_only_guard_present")),\n        "approved_for_runtime_overlay_activation_candidate": False,\n        "approved_for_parameter_relaxation_candidate": False,\n        "approved_for_paper_candidate": False,\n        "approved_for_live_real": False,\n        "runtime_overlay_activation_performed": False,\n        "strategy_parameter_mutation_performed": False,\n        "scheduler_mutation_performed": False,\n        "training_performed": False,\n        "reload_performed": False,\n        "trading_action_performed": False,\n        "paper_live_order_enablement_present": False,\n        "checks": report["checks"],\n        "module_probe": report.get("module_probe", {}),\n        "recommendation": "Use this gate only for deterministic replay/OOS promotion review. Do not infer live readiness or enable runtime/paper/live from this report.",\n    }\n    reports_dir = Path(args.reports_dir)\n    reports_dir.mkdir(parents=True, exist_ok=True)\n    json_path = reports_dir / f"4B436629D_replay_backtest_walkforward_gate_decision_{now}.json"\n    md_path = json_path.with_suffix(".md")\n    json_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2, sort_keys=True), encoding="utf-8", newline="\\n")\n    md_path.write_text(\n        "# 4B.4.3.6.6.29D Replay / Backtest / Walk-forward Gate Decision Report\\n\\n"\n        f"- decision: `{payload[\'decision\']}`\\n"\n        f"- read_only: `{payload[\'read_only\']}`\\n"\n        f"- approved_for_live_real: `{payload[\'approved_for_live_real\']}`\\n"\n        f"- trading_action_performed: `{payload[\'trading_action_performed\']}`\\n",\n        encoding="utf-8",\n        newline="\\n",\n    )\n    print(f"{CONTRACT_VERSION} Replay / Backtest / Walk-forward Gate {payload[\'decision\']}")\n    for key in (\n        "read_only", "approved_for_deterministic_replay_baseline", "approved_for_model_artifact_hash_baseline",\n        "approved_for_last_known_good_registry_baseline", "approved_for_walk_forward_gate_baseline",\n        "approved_for_oos_report_gate_baseline", "approved_for_runtime_overlay_activation_candidate",\n        "approved_for_parameter_relaxation_candidate", "approved_for_paper_candidate", "approved_for_live_real",\n        "training_performed", "reload_performed", "trading_action_performed",\n    ):\n        print(f" - {key}: {payload[key]}")\n    print(f"report_json: {json_path}")\n    print(f"report_md: {md_path}")\n    return 0 if payload["ok"] else 2\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'tools/rollback_4B436629D_replay_backtest_walkforward_gate.py': 'from __future__ import annotations\n\nfrom pathlib import Path\n\nFILES = [\n    "src/tradebot/replay_gate.py",\n    "tests/test_replay_backtest_walkforward_gate_4B436629D.py",\n    "tools/apply_4B436629D_replay_backtest_walkforward_gate.py",\n    "tools/check_4B436629D_replay_backtest_walkforward_gate.py",\n    "tools/run_4B436629D_replay_backtest_walkforward_gate.py",\n    "tools/rollback_4B436629D_replay_backtest_walkforward_gate.py",\n    "docs/REPLAY_BACKTEST_WALKFORWARD_GATE_4B436629D.md",\n]\n\n\ndef main() -> int:\n    root = Path.cwd()\n    for rel in FILES:\n        path = root / rel\n        if path.exists():\n            path.unlink()\n    print("4B.4.3.6.6.29D replay/backtest/walk-forward gate files removed; config fields are left for manual review")\n    return 0\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'docs/REPLAY_BACKTEST_WALKFORWARD_GATE_4B436629D.md': '# 4B.4.3.6.6.29D Replay / Backtest / Walk-forward Gate\n\nAdds deterministic replay primitives, model artifact SHA-256 manifests, a last-known-good model registry helper, and an OOS report gate.\n\nSafety: read-only production hardening baseline; no runtime activation, no paper/live/live-real, no orders, no HYP-006 threshold mutation.\n', 'src/tradebot/replay_gate.py': 'from __future__ import annotations\n\nimport hashlib\nimport json\nfrom dataclasses import asdict, dataclass\nfrom pathlib import Path\nfrom typing import Any, Iterable, Mapping\n\nREPLAY_GATE_CONTRACT_VERSION = "4B.4.3.6.6.29D"\nRUNTIME_ACTIVATION_BLOCKED_BY_REPLAY_GATE = True\nPAPER_LIVE_ORDER_BLOCKED_BY_REPLAY_GATE = True\nTRAINING_RELOAD_BLOCKED_BY_REPLAY_GATE = True\n\n\n@dataclass(frozen=True, slots=True)\nclass ReplayDigest:\n    contract_version: str\n    ok: bool\n    row_count: int\n    digest: str\n    deterministic_replay: bool\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\n@dataclass(frozen=True, slots=True)\nclass ModelArtifactManifest:\n    contract_version: str\n    ok: bool\n    model_path: str\n    sha256: str\n    byte_size: int\n    metadata: dict[str, Any]\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\n@dataclass(frozen=True, slots=True)\nclass WalkForwardWindow:\n    window_id: int\n    train_start: int\n    train_end: int\n    test_start: int\n    test_end: int\n\n    def to_dict(self) -> dict[str, int]:\n        return asdict(self)\n\n\n@dataclass(frozen=True, slots=True)\nclass OOSGateDecision:\n    contract_version: str\n    ok: bool\n    approved_for_promotion_review_candidate: bool\n    approved_for_runtime_overlay_activation_candidate: bool\n    approved_for_parameter_relaxation_candidate: bool\n    approved_for_paper_candidate: bool\n    approved_for_live_real: bool\n    runtime_activation_blocked: bool\n    paper_live_order_blocked: bool\n    training_reload_blocked: bool\n    reason_codes: list[str]\n    metrics: dict[str, Any]\n    thresholds: dict[str, Any]\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\ndef _canonical_payload(payload: Any) -> str:\n    return json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))\n\n\ndef deterministic_decision_replay_digest(rows: Iterable[Mapping[str, Any]]) -> ReplayDigest:\n    normalized = [dict(row) for row in rows]\n    digest = hashlib.sha256(_canonical_payload(normalized).encode("utf-8")).hexdigest()\n    return ReplayDigest(REPLAY_GATE_CONTRACT_VERSION, True, len(normalized), digest, True)\n\n\ndef verify_replay_digest(rows: Iterable[Mapping[str, Any]], expected_digest: str) -> ReplayDigest:\n    digest = deterministic_decision_replay_digest(rows)\n    ok = digest.digest == str(expected_digest or "").strip()\n    return ReplayDigest(digest.contract_version, ok, digest.row_count, digest.digest, ok)\n\n\ndef hash_model_artifact(model_path: str | Path, *, metadata: Mapping[str, Any] | None = None) -> ModelArtifactManifest:\n    path = Path(model_path)\n    if not path.exists() or not path.is_file():\n        raise FileNotFoundError(f"Model artifact not found: {path}")\n    hasher = hashlib.sha256()\n    byte_size = 0\n    with path.open("rb") as fh:\n        for chunk in iter(lambda: fh.read(1024 * 1024), b""):\n            byte_size += len(chunk)\n            hasher.update(chunk)\n    return ModelArtifactManifest(REPLAY_GATE_CONTRACT_VERSION, True, path.as_posix(), hasher.hexdigest(), byte_size, dict(metadata or {}))\n\n\ndef build_walk_forward_windows(*, total_samples: int, train_size: int, test_size: int, step_size: int | None = None) -> list[WalkForwardWindow]:\n    total, train, test = int(total_samples), int(train_size), int(test_size)\n    step = int(step_size or test)\n    if total <= 0 or train <= 0 or test <= 0 or step <= 0:\n        raise ValueError("total_samples, train_size, test_size and step_size must be positive")\n    windows: list[WalkForwardWindow] = []\n    start = 0\n    idx = 1\n    while start + train + test <= total:\n        windows.append(WalkForwardWindow(idx, start, start + train, start + train, start + train + test))\n        start += step\n        idx += 1\n    return windows\n\n\ndef _float_metric(metrics: Mapping[str, Any], key: str, default: float = 0.0) -> float:\n    try:\n        return float(metrics.get(key, default))\n    except (TypeError, ValueError):\n        return default\n\n\ndef _int_metric(metrics: Mapping[str, Any], key: str, default: int = 0) -> int:\n    try:\n        return int(metrics.get(key, default))\n    except (TypeError, ValueError):\n        return default\n\n\ndef evaluate_oos_report_gate(\n    metrics: Mapping[str, Any],\n    *,\n    min_matured_count: int = 30,\n    min_win_rate_pct: float = 60.0,\n    min_profit_factor: float = 1.5,\n    min_mean_return_bps: float = 0.0,\n    min_worst_return_bps: float = -500.0,\n    min_worst_mae_bps: float = -500.0,\n    min_unique_days: int = 3,\n    min_regime_count: int = 2,\n) -> OOSGateDecision:\n    snapshot = dict(metrics)\n    thresholds = {\n        "min_matured_count": int(min_matured_count),\n        "min_win_rate_pct": float(min_win_rate_pct),\n        "min_profit_factor": float(min_profit_factor),\n        "min_mean_return_bps": float(min_mean_return_bps),\n        "min_worst_return_bps": float(min_worst_return_bps),\n        "min_worst_mae_bps": float(min_worst_mae_bps),\n        "min_unique_days": int(min_unique_days),\n        "min_regime_count": int(min_regime_count),\n    }\n    reasons: list[str] = []\n    if _int_metric(snapshot, "matured_count") < min_matured_count:\n        reasons.append("OOS_MATURED_COUNT_BELOW_MIN")\n    if _float_metric(snapshot, "win_rate_pct") < min_win_rate_pct:\n        reasons.append("OOS_WIN_RATE_BELOW_MIN")\n    if _float_metric(snapshot, "profit_factor") < min_profit_factor:\n        reasons.append("OOS_PROFIT_FACTOR_BELOW_MIN")\n    if _float_metric(snapshot, "mean_return_bps") <= min_mean_return_bps:\n        reasons.append("OOS_MEAN_RETURN_NOT_POSITIVE")\n    if _float_metric(snapshot, "worst_return_bps") < min_worst_return_bps:\n        reasons.append("OOS_WORST_RETURN_BELOW_MIN")\n    if _float_metric(snapshot, "worst_mae_bps") < min_worst_mae_bps:\n        reasons.append("OOS_WORST_MAE_BELOW_MIN")\n    if _int_metric(snapshot, "unique_oos_days", _int_metric(snapshot, "unique_days")) < min_unique_days:\n        reasons.append("OOS_UNIQUE_DAY_COUNT_BELOW_MIN")\n    if _int_metric(snapshot, "regime_count") < min_regime_count:\n        reasons.append("OOS_REGIME_COUNT_BELOW_MIN")\n    if bool(snapshot.get("duplicate_or_stagnation_detected", False)):\n        reasons.append("OOS_DUPLICATE_OR_STAGNATION_DETECTED")\n    if bool(snapshot.get("tail_risk_worsened", False)):\n        reasons.append("OOS_TAIL_RISK_WORSENED")\n    if bool(snapshot.get("measurement_guard_pass", True)) is False:\n        reasons.append("OOS_MEASUREMENT_GUARD_FAILED")\n    review = not reasons\n    return OOSGateDecision(\n        contract_version=REPLAY_GATE_CONTRACT_VERSION,\n        ok=True,\n        approved_for_promotion_review_candidate=review,\n        approved_for_runtime_overlay_activation_candidate=False,\n        approved_for_parameter_relaxation_candidate=False,\n        approved_for_paper_candidate=False,\n        approved_for_live_real=False,\n        runtime_activation_blocked=True,\n        paper_live_order_blocked=True,\n        training_reload_blocked=True,\n        reason_codes=reasons or ["OOS_GATE_PROMOTION_REVIEW_CANDIDATE_ONLY"],\n        metrics=snapshot,\n        thresholds=thresholds,\n    )\n\n\ndef load_last_known_good_registry(registry_path: str | Path) -> dict[str, Any]:\n    path = Path(registry_path)\n    if not path.exists():\n        return {"contract_version": REPLAY_GATE_CONTRACT_VERSION, "models": []}\n    payload = json.loads(path.read_text(encoding="utf-8"))\n    if not isinstance(payload, dict):\n        raise ValueError("Last-known-good registry must be a JSON object")\n    payload.setdefault("contract_version", REPLAY_GATE_CONTRACT_VERSION)\n    payload.setdefault("models", [])\n    if not isinstance(payload["models"], list):\n        raise ValueError("Last-known-good registry models must be a list")\n    return payload\n\n\ndef register_last_known_good_model(\n    registry_path: str | Path,\n    manifest: ModelArtifactManifest | Mapping[str, Any],\n    *,\n    reason: str,\n    gate_snapshot: Mapping[str, Any] | None = None,\n) -> dict[str, Any]:\n    path = Path(registry_path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    registry = load_last_known_good_registry(path)\n    manifest_payload = manifest.to_dict() if hasattr(manifest, "to_dict") else dict(manifest)\n    entry = {"contract_version": REPLAY_GATE_CONTRACT_VERSION, "reason": str(reason or "").strip() or "LKG_REGISTERED", "manifest": manifest_payload, "gate_snapshot": dict(gate_snapshot or {})}\n    registry["models"].append(entry)\n    registry["latest"] = entry\n    path.write_text(_canonical_payload(registry) + "\\n", encoding="utf-8", newline="\\n")\n    return registry\n\n\ndef build_replay_gate_snapshot(metrics: Mapping[str, Any], model_path: str | Path | None = None) -> dict[str, Any]:\n    decision = evaluate_oos_report_gate(metrics)\n    payload: dict[str, Any] = {"contract_version": REPLAY_GATE_CONTRACT_VERSION, "ok": True, "decision": decision.to_dict(), "runtime_activation_blocked": True, "paper_live_order_blocked": True, "training_reload_blocked": True}\n    if model_path is not None:\n        payload["model_artifact"] = hash_model_artifact(model_path).to_dict()\n    return payload\n'}
CONFIG_FIELDS = """
    # 4B.4.3.6.6.29D replay/backtest/walk-forward gate controls
    replay_gate_enabled: bool = True
    deterministic_replay_required: bool = True
    model_artifact_hash_required: bool = True
    walk_forward_oos_gate_required: bool = True
    last_known_good_model_registry_path: str = "models/last_known_good_model_registry.json"
    replay_gate_min_oos_samples: int = 30
    replay_gate_min_oos_win_rate_pct: float = 60.0
    replay_gate_min_oos_profit_factor: float = 1.5
    replay_gate_min_oos_mean_return_bps: float = 0.0
    replay_gate_min_oos_worst_return_bps: float = -500.0
    replay_gate_min_oos_worst_mae_bps: float = -500.0
    replay_gate_min_unique_oos_days: int = 3
    replay_gate_min_regime_count: int = 2
"""


def _write(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8", newline="\n")


def _patch_config(path: Path) -> bool:
    text = path.read_text(encoding="utf-8")
    if "replay_gate_enabled" in text:
        return True
    marker = "    promotion_gate_isolation_enabled: bool = True\n"
    if marker not in text:
        raise RuntimeError("Could not find 29A production hardening config marker")
    path.write_text(text.replace(marker, marker + CONFIG_FIELDS.rstrip() + "\n", 1), encoding="utf-8", newline="\n")
    return True


def main() -> int:
    root = Path.cwd()
    for rel, content in FILES.items():
        _write(root / rel, content)
    patched_config = _patch_config(root / "src/tradebot/config.py")
    from check_4B436629D_replay_backtest_walkforward_gate import build_report
    report = build_report(root)
    print(json.dumps(report, ensure_ascii=False, indent=2, sort_keys=True))
    print(f"{CONTRACT_VERSION} Replay / Backtest / Walk-forward Gate patch applied")
    for key in ("all_expected_files_present", "all_py_compile_ok", "deterministic_replay_digest_present", "model_artifact_hash_present", "last_known_good_registry_present", "walk_forward_gate_present", "oos_report_gate_present", "promotion_review_only_guard_present", "config_replay_gate_fields_present", "module_probe_ok", "runtime_activation_blocked", "paper_live_order_blocked", "training_reload_blocked"):
        print(f" - {key}: {report['checks'].get(key)}")
    print(f" - patched_config_replay_gate_fields: {patched_config}")
    print(" - runtime_overlay_activation_performed: False")
    print(" - training_performed: False")
    print(" - reload_performed: False")
    print(" - trading_action_performed: False")
    print(" - paper_live_order_enablement_present: False")
    return 0 if report["ok"] else 2


if __name__ == "__main__":
    raise SystemExit(main())
